const setCookie = (name: string, value: string, days: number) => {
    const expires = new Date();
    expires.setTime(expires.getTime() + (days * 24 * 60 * 60 * 1000));
    document.cookie = `${name}=${value};expires=${expires.toUTCString()};path=/;SameSite=Strict`;
};

const getCookie = (name: string) => {
    const nameEQ = name + "=";
    const ca = document.cookie.split(';');
    for(let i=0;i < ca.length;i++) {
        let c = ca[i];
        while (c.charAt(0) === ' ') c = c.substring(1,c.length);
        if (c.indexOf(nameEQ) === 0) return c.substring(nameEQ.length,c.length);
    }
    return null;
};

// Genera un hash simple para convertir strings largos en IDs cortos
const cyrb53 = (str: string, seed = 0) => {
    let h1 = 0xdeadbeef ^ seed, h2 = 0x41c6ce57 ^ seed;
    for (let i = 0, ch; i < str.length; i++) {
        ch = str.charCodeAt(i);
        h1 = Math.imul(h1 ^ ch, 2654435761);
        h2 = Math.imul(h2 ^ ch, 1597334677);
    }
    h1 = Math.imul(h1 ^ (h1 >>> 16), 2246822507);
    h1 ^= Math.imul(h2 ^ (h2 >>> 13), 3266489909);
    h2 = Math.imul(h2 ^ (h2 >>> 16), 2246822507);
    h2 ^= Math.imul(h1 ^ (h1 >>> 13), 3266489909);
    return (h2 >>> 0).toString(16).padStart(8, '0') + (h1 >>> 0).toString(16).padStart(8, '0');
};

export const normalizeString = (str: string) => {
    return str ? str.normalize("NFD").replace(/[\u0300-\u036f]/g, "").toUpperCase().trim() : "";
};

export const appwriteService = {

  // --- MOTOR DE IDENTIDAD DE HARDWARE DETERMINISTA ---
  getDeviceId(): string {
    // 1. Intentar recuperar de LocalStorage o Cookies
    let deviceId = localStorage.getItem(STORAGE_KEY_DEVICE_ID) || getCookie(STORAGE_KEY_DEVICE_ID);

    if (!deviceId) {
        // 2. Si no hay nada guardado, calculamos la huella digital del hardware
        // Obtenemos specs físicas que no cambian aunque se borre el caché
        const screenSpecs = `${window.screen.width}x${window.screen.height}x${window.screen.colorDepth}`;
        const cpuCores = navigator.hardwareConcurrency || 4;
        const platform = navigator.platform || 'unknown';
        const language = navigator.language || 'es';

        // Canvas Fingerprinting (Unico por GPU/Drivers)
        let canvasHash = '';
        try {
            const canvas = document.createElement('canvas');
            const ctx = canvas.getContext('2d');
            if (ctx) {
                canvas.width = 200;
                canvas.height = 50;
                ctx.textBaseline = "top";
                ctx.font = "14px 'Arial'";
                ctx.textBaseline = "alphabetic";
                ctx.fillStyle = "#f60";
                ctx.fillRect(125,1,62,20);
                ctx.fillStyle = "#069";
                ctx.fillText("CODEX_SECURE_ID", 2, 15);
                ctx.fillStyle = "rgba(102, 204, 0, 0.7)";
                ctx.fillText("CODEX_SECURE_ID", 4, 17);
                canvasHash = canvas.toDataURL().slice(-50); // Usamos el final del base64 como parte de la huella
            }
        } catch (e) {}

        // Creamos una semilla única basada en la máquina física
        const machineFingerprint = `${screenSpecs}-${cpuCores}-${platform}-${language}-${canvasHash}`;
        const shortHash = cyrb53(machineFingerprint).toUpperCase().substring(0, 12);

        deviceId = `CDX-${shortHash}`;
    }

    // 3. Persistencia doble cruzada (Sincronizar LocalStorage y Cookies)
    localStorage.setItem(STORAGE_KEY_DEVICE_ID, deviceId);
    setCookie(STORAGE_KEY_DEVICE_ID, deviceId, 3650); // Expira en 10 años

    return deviceId;
  },

  async isThisAdminHardware(): Promise<boolean> {
    const hasMasterSeal = localStorage.getItem(STORAGE_KEY_MASTER_SEAL) === 'SECURE_MASTER_AUTHORIZED';
    if (hasMasterSeal) return true;
    const currentDeviceId = this.getDeviceId();
    if (ADMIN_HARDWARE_IDS.includes(currentDeviceId)) return true;
    if (!isLegacyReady() || !supabase) return false;
    try {
        const { data: owners } = await supabase
            .from('user_authorized_ips')
            .select('user_id')
            .eq('ip_address', currentDeviceId);
        if (!owners || owners.length === 0) return false;
        const ownerIds = owners.map(o => o.user_id);
        const { data: adminCheck } = await supabase
            .from('users')
            .select('email')
            .in('id', ownerIds);
        return adminCheck?.some(u => ADMIN_EMAILS.includes(u.email.toLowerCase())) || false;
    } catch (e) { return false; }
  },

