            await supabase.auth.signOut();
            throw new Error("ACCESO DENEGADO: Su cuenta no está autorizada en CODEX.");
        }

        const isAdminByRole = profileData.role === 'admin';
        const isFullAdmin = isAdminByEmail || isAdminByRole;
