            maxDevices: profileData?.max_devices || (isFullAdmin ? 10 : 3),
            isAdminHardware: isAdminHardware || isFullAdmin
        };
      } catch (error: any) { throw error; }
    }
    throw new Error("Error de conexión.");
  },

