  async getCommunityContributions(allowedAreas: string[], isAdmin: boolean = false): Promise<CommunityContribution[]> {
    if (!isLegacyReady() || !supabase) return [];
    try {
        let query = supabase.from('community_contributions').select('*').order('created_at', { ascending: false });

        const { data, error } = await query;
        if (error) return [];

        const mapped = data as CommunityContribution[];

        if (isAdmin) return mapped;

        const normalizedAllowed = allowedAreas.map(a => normalizeString(a));
        return mapped.filter(c => 
            c.status === 'approved' && normalizedAllowed.includes(normalizeString(c.area))
        );
    } catch (e) { return []; }
  },

