      const { error } = await supabase.from('download_requests').update({ status: 'consumed' }).eq('id', requestId);
      return !error;
    }
    return false;
  },

  async adminGetDownloadRequests(): Promise<DownloadRequest[]> {
    if (isLegacyReady() && supabase) {
       const { data, error } = await supabase.from('download_requests').select(`*, users (name, email, area)`).in('status', ['pending', 'approved', 'consumed']).order('requested_at', { ascending: false });
       if (error) return [];
       return data.map((r: any) => ({
         id: r.id, user_id: r.user_id, procedure_id: r.procedure_id, procedure_name: r.procedure_name, status: r.status, requested_at: r.requested_at, user_name: r.users?.name || 'Usuario', user_email: r.users?.email || 'N/A', user_area: (r.users?.area || 'N/A').toUpperCase()
       }));
    }
    return [];
  },

  async adminRespondToDownloadRequest(id: string, status: 'approved' | 'rejected'): Promise<boolean> {
    if (isLegacyReady() && supabase) {
      const { error = null } = await supabase.from('download_requests').update({ status, responded_at: new Date().toISOString() }).eq('id', id);
      return !error;
    }
    return false;
  },

  async adminDeleteDownloadRequest(id: string): Promise<boolean> {
    if (isLegacyReady() && supabase) {
        const { error = null } = await supabase.from('download_requests').delete().eq('id', id);
        return !error;
    }
    return false;
  },

  async adminGetAllUsers(): Promise<User[]> {
    if (isLegacyReady() && supabase) {
      try {
          const [usersRes, signaturesRes, devicesRes, accessRes] = await Promise.all([
              supabase.from('users').select('*').order('created_at', { ascending: false }),
              supabase.from('privacy_signatures').select('*'),
              supabase.from('user_authorized_ips').select('user_id, ip_address'),
              supabase.from('user_area_access').select('user_id, area_name')
          ]);
          const sm = new Map();
          signaturesRes.data?.forEach((sig: any) => sm.set(sig.user_id, sig));
          const dm = new Map();
          devicesRes.data?.forEach((dev: any) => {
              if(!dm.has(dev.user_id)) dm.set(dev.user_id, []);
              dm.get(dev.user_id).push(dev.ip_address);
          });
          const am = new Map<string, string[]>();
          accessRes.data?.forEach((acc: any) => {
              if(!am.has(acc.user_id)) am.set(acc.user_id, []);
              am.get(acc.user_id)!.push((acc.area_name || '').toUpperCase());
          });
          return (usersRes.data || []).map((u: any) => {
              const primaryArea = (u.area || '').toUpperCase();
              let allowedAreas = am.get(u.id) || [primaryArea];
              if (allowedAreas.length === 0 && primaryArea) allowedAreas = [primaryArea];
              return {
                  $id: u.id, name: u.name, email: u.email, area: primaryArea, allowedAreas: Array.from(new Set(allowedAreas)), role: u.role, privacyAccepted: sm.has(u.id), signedName: sm.get(u.id)?.signed_name, signedDepartment: sm.get(u.id)?.signed_department, lastIp: u.last_ip || 'N/A', lastDeviceId: u.last_device_id || 'N/A', authorizedDevices: dm.get(u.id) || [], avatarUrl: u.avatar_url, maxDevices: u.max_devices || 3
              };
          });
      } catch (e) { return []; }
    }
    return [];
  },

  async adminDeleteAuthorizedDevice(userId: string, deviceId: string): Promise<boolean> {
      if (isLegacyReady() && supabase) {
          const { error } = await supabase.from('user_authorized_ips').delete().eq('user_id', userId).eq('ip_address', deviceId);
          return !error;
      }
      return false;
  },

  async adminUpdateUserAreas(userId: string, areas: string[]): Promise<boolean> {
    if (isLegacyReady() && supabase) {
        try {
            const { error: delError } = await supabase.from('user_area_access').delete().eq('user_id', userId);
            if (delError) throw delError;

            if (areas.length > 0) {
                const inserts = areas.map(area => ({ user_id: userId, area_name: area.toUpperCase() }));
                const { error: insError } = await supabase.from('user_area_access').insert(inserts);
                if (insError) throw insError;
            }
            return true;
        } catch (e) {
            console.error("Error updating user areas", e);
            return false;
        }
    }
    return false;
  },

  async logProcedureAccess(userId: string, procedureId: string, procedureName: string, area: string): Promise<string | null> {
    if (isLegacyReady() && supabase) {
      try {
        const { data, error } = await supabase.from('procedure_access_logs').insert({ user_id: userId, procedure_id: procedureId, procedure_name: procedureName, area: area, accessed_at: new Date().toISOString(), duration_seconds: 0 }).select('id').single();
        return data ? data.id : null;
      } catch (e) { return null; }
    }
    return null;
  },

  async updateAccessDuration(logId: string, durationSeconds: number): Promise<void> {
    if (isLegacyReady() && supabase && logId) {
        supabase.from('procedure_access_logs').update({ duration_seconds: durationSeconds }).eq('id', logId).then();
    }
  },

  async adminDeleteAllAccessLogs(): Promise<boolean> {
      if (isLegacyReady() && supabase) {
          const { error } = await supabase.from('procedure_access_logs').delete().neq('id', '00000000-0000-0000-0000-000000000000'); 
          return !error;
      }
      return false;
  },

  async getAdminAnalytics(): Promise<AccessLog[]> {
    if (isLegacyReady() && supabase) {
      try {
        const { data: logs } = await supabase.from('procedure_access_logs').select('*').order('accessed_at', { ascending: false }).limit(2000); 
        if (!logs) return [];
        const uids = [...new Set(logs.map((l: any) => l.user_id))];
        let um: Record<string, any> = {};
        if (uids.length > 0) {
            const { data } = await supabase.from('users').select('id, name, email').in('id', uids);
            data?.forEach((u: any) => um[u.id] = u);
        }
        return logs.map((log: any) => ({
          id: log.id, user_id: log.user_id, procedure_id: log.procedure_id, procedure_name: log.procedure_name, area: log.area, accessed_at: log.accessed_at, duration_seconds: log.duration_seconds || 0, user_name: um[log.user_id]?.name || 'N/A', user_email: um[log.user_email] || 'N/A'
        }));
      } catch (e) { return []; }
    }
    return [];
  },

  async createImprovementProposal(proposal: any): Promise<boolean> {
    if (isLegacyReady() && supabase) {
        const { error } = await supabase.from('improvement_proposals').insert({ ...proposal, status: 'pending' });
        return !error;
    }
    return false;
  },

  async getUserProposals(userId: string): Promise<ImprovementProposal[]> {
    if (isLegacyReady() && supabase) {
        const { data } = await supabase.from('improvement_proposals').select('*').eq('user_id', userId).order('created_at', { ascending: false });
        return (data as ImprovementProposal[]) || [];
    }
    return [];
  },

  async adminGetProposals(): Promise<ImprovementProposal[]> {
      if (isLegacyReady() && supabase) {
          const { data: p } = await supabase.from('improvement_proposals').select('*').order('created_at', { ascending: false });
          if (!p) return [];
          const uids = [...new Set(p.map((p: any) => p.user_id))];
          let um: Record<string, any> = {};
          if (uids.length > 0) {
            const { data } = await supabase.from('users').select('id, name, email, avatar_url').in('id', uids);
            data?.forEach((u: any) => um[u.id] = u);
          }
          return p.map((p: any) => ({
              ...p, user_name: um[p.user_id]?.name || 'N/A', user_email: um[p.user_id]?.email || 'N/A', user_avatar: um[p.user_id]?.avatar_url
          }));
      }
      return [];
  },

  async adminUpdateProposalStatus(id: string, status: string, feedback: string): Promise<boolean> {
      if (isLegacyReady() && supabase) {
          const { error = null } = await supabase.from('improvement_proposals').update({ status, admin_feedback: feedback }).eq('id', id);
          return !error;
      }
      return false;
  },

  async adminDeleteProposal(id: string): Promise<boolean> {
    if (isLegacyReady() && supabase) {
        const { error = null } = await supabase.from('improvement_proposals').delete().eq('id', id);
        return !error;
    }
    return false;
  },

  // --- SERVICIOS DE REPOSITORIO COMUNITARIO (APORTACIONES) ---

  async uploadCommunityFile(file: File): Promise<string | null> {
    if (!isLegacyReady() || !supabase) return null;
    try {
        const fileExt = file.name.split('.').pop();
        const fileName = `contribution_${Date.now()}_${Math.random().toString(36).substring(2, 7)}.${fileExt}`;
        const { error: uploadError } = await supabase.storage
            .from('community-files')
            .upload(fileName, file);

        if (uploadError) throw uploadError;

        const { data } = supabase.storage
            .from('community-files')
            .getPublicUrl(fileName);

        return data.publicUrl;
    } catch (e) {
        console.error("Error uploading community file", e);
        return null;
    }
  },

  async createCommunityContribution(contribution: Partial<CommunityContribution>): Promise<boolean> {
      if (!isLegacyReady() || !supabase) return false;
      const { error } = await supabase.from('community_contributions').insert({
          ...contribution,
          status: 'pending',
          device_id: this.getDeviceId()
      });
      return !error;
  },

  async getCommunityContributions(allowedAreas: string[], isAdmin: boolean = false): Promise<CommunityContribution[]> {
    if (!isLegacyReady() || !supabase) return [];
    try {
        let query = supabase.from('community_contributions').select('*').order('created_at', { ascending: false });

        // --- SEGMENTACIÓN DE SEGURIDAD POR ÁREA ---
        if (!isAdmin) {
            const upperAllowed = allowedAreas.map(a => a.toUpperCase());
            query = query.in('area', upperAllowed).eq('status', 'approved');
        }

        const { data, error } = await query;
        if (error) return [];

        return data as CommunityContribution[];
    } catch (e) { return []; }
  },

  async adminGetPendingContributions(): Promise<CommunityContribution[]> {
      if (!isLegacyReady() || !supabase) return [];
      const { data } = await supabase.from('community_contributions').select('*').eq('status', 'pending').order('created_at', { ascending: false });
      return (data as CommunityContribution[]) || [];
  },

  async adminUpdateContributionStatus(id: string, status: 'approved' | 'rejected'): Promise<boolean> {
      if (!isLegacyReady() || !supabase) return false;
      const { error } = await supabase.from('community_contributions').update({ status }).eq('id', id);
      return !error;
  },

  async adminDeleteContribution(id: string): Promise<boolean> {
      if (!isLegacyReady() || !supabase) return false;
      const { error } = await supabase.from('community_contributions').delete().eq('id', id);
      return !error;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { useAuth } from '../context/AuthContext';
import { appwriteService, normalizeString } from '../services/appwriteService';
import { CommunityContribution, ADMIN_EMAILS } from '../types';
import { 
  Upload, FileText, Download, CheckCircle, Clock, XCircle, 
  Search, Shield, AlertTriangle, X, Loader, Plus, Filter,
  FileSpreadsheet, Image as ImageIcon, FileBox, ExternalLink,
  ChevronRight, Trash2, Eye, HardDrive, Info, Lock
} from 'lucide-react';

export const CommunityContributions: React.FC = () => {
  const { user } = useAuth();
  const [contributions, setContributions] = useState<CommunityContribution[]>([]);
  const [loading, setLoading] = useState(true);
  const [showUploadModal, setShowUploadModal] = useState(false);
  const [uploading, setUploading] = useState(false);

  // Form State
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [selectedArea, setSelectedArea] = useState('');
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Filter State
  const [searchTerm, setSearchTerm] = useState('');
  const [areaFilter, setAreaFilter] = useState('all');

  const isAdmin = user?.role === 'admin' || (user?.email && ADMIN_EMAILS.some(e => e.toLowerCase() === user.email.toLowerCase()));

  useEffect(() => {
    if (user) {
        setSelectedArea(user.area);
        loadData();
    }
  }, [user]);

  const loadData = async () => {
    if (!user) return;
    setLoading(true);
    const data = await appwriteService.getCommunityContributions(user.allowedAreas, !!isAdmin);
    setContributions(data);
    setLoading(false);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
        const ext = file.name.split('.').pop()?.toLowerCase();
        const allowed = ['pdf', 'xlsx', 'xls', 'docx', 'doc', 'png', 'jpg', 'jpeg'];
        if (!allowed.includes(ext || '')) {
            alert("Extensión de archivo no permitida. Solo PDF, Excel, Word e Imágenes.");
            e.target.value = '';
            return;
        }
        setSelectedFile(file);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!user || !selectedFile || !title.trim()) return;

    setUploading(true);
    try {
        const fileUrl = await appwriteService.uploadCommunityFile(selectedFile);
        if (!fileUrl) throw new Error("Error subiendo archivo");

        const ext = selectedFile.name.split('.').pop()?.toLowerCase();
        let fileType: any = 'pdf';
        if (['xlsx', 'xls'].includes(ext || '')) fileType = 'excel';
        else if (['docx', 'doc'].includes(ext || '')) fileType = 'word';
        else if (['png', 'jpg', 'jpeg'].includes(ext || '')) fileType = 'image';

        const success = await appwriteService.createCommunityContribution({
            user_id: user.$id,
            user_name: user.name,
            title: title.trim(),
            description: description.trim(),
            file_url: fileUrl,
            file_type: fileType,
            area: selectedArea,
        });

        if (success) {
            setShowUploadModal(false);
            setTitle('');
            setDescription('');
            setSelectedFile(null);
            loadData();
        } else {
            alert("Error al registrar la aportación.");
        }
    } catch (e) {
        alert("Ocurrió un error inesperado.");
    } finally {
        setUploading(false);
    }
  };

  const handleModeration = async (id: string, status: 'approved' | 'rejected') => {
      const success = await appwriteService.adminUpdateContributionStatus(id, status);
      if (success) {
          loadData();
      }
  };

  const handleDelete = async (id: string) => {
      if (window.confirm("¿Estás seguro de eliminar este aporte permanentemente?")) {
          const success = await appwriteService.adminDeleteContribution(id);
          if (success) loadData();
      }
  };

  const getFileIcon = (type: string) => {
    switch (type) {
        case 'excel': return <FileSpreadsheet className="text-emerald-500" size={32} />;
        case 'word': return <FileText className="text-blue-500" size={32} />;
        case 'image': return <ImageIcon className="text-purple-500" size={32} />;
        default: return <FileText className="text-red-500" size={32} />;
    }
  };

  const filtered = contributions.filter(c => {
      const matchesSearch = c.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          c.description.toLowerCase().includes(searchTerm.toLowerCase()) ||
                          c.user_name.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesArea = areaFilter === 'all' ? true : normalizeString(c.area) === normalizeString(areaFilter);
      return matchesSearch && matchesArea;
  });

  return (
    <div className="max-w-7xl mx-auto space-y-8 animate-in fade-in duration-500">

      {/* HEADER SECTION */}
      <div className="bg-slate-900 p-6 rounded-3xl border border-white/10 flex flex-col md:flex-row justify-between items-center gap-6 shadow-xl relative overflow-hidden">
          <div className="absolute top-0 left-0 w-1 h-full bg-indigo-500"></div>
          <div className="flex items-center gap-4">
              <div className="p-3 bg-indigo-900/30 rounded-2xl text-indigo-400 border border-indigo-500/20">
                  <HardDrive size={32} />
              </div>
              <div>
                  <h1 className="text-2xl font-black text-white uppercase tracking-tighter leading-none">Repositorio Comunitario</h1>
                  <p className="text-gray-400 text-sm mt-1 uppercase tracking-widest font-bold">Aportaciones Operativas de Colaboradores</p>
              </div>
          </div>

          <div className="flex flex-wrap items-center gap-3">
              <button 
                onClick={() => setShowUploadModal(true)}
                className="flex items-center px-6 py-3 bg-indigo-600 hover:bg-indigo-500 text-white rounded-2xl font-black text-xs uppercase tracking-widest transition-all shadow-lg shadow-indigo-950/40"
              >
                  <Plus size={18} className="mr-2" />
                  Nueva Aportación
              </button>
          </div>
      </div>

      {/* PRIVACY INDICATOR BANNER */}
      {!isAdmin && (
        <div className="bg-indigo-950/20 border border-indigo-500/20 rounded-2xl p-4 flex items-center gap-3 shadow-inner">
            <Lock size={18} className="text-indigo-400 shrink-0" />
            <p className="text-xs font-bold text-indigo-300 uppercase tracking-wide">
                Modo Privacidad Activo: Estás visualizando aportes exclusivos de tus áreas autorizadas ({user?.allowedAreas.join(', ')}).
            </p>
        </div>
      )}

      {/* FILTER BAR */}
      <div className="flex flex-col md:flex-row gap-4 bg-slate-900/50 p-4 rounded-2xl border border-white/5">
          <div className="relative flex-1">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
              <input 
                type="text" 
                placeholder="Buscar archivos, autores o descripciones..."
                className="w-full bg-slate-800 border border-white/10 rounded-xl py-3 pl-12 pr-4 text-sm text-white focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
          </div>
          <div className="flex gap-2">
              <div className="relative">
                  <Filter className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" size={14} />
                  <select 
                    value={areaFilter}
                    onChange={(e) => setAreaFilter(e.target.value)}
                    className="bg-slate-800 border border-white/10 rounded-xl py-3 pl-10 pr-8 text-xs font-bold text-gray-300 uppercase outline-none focus:ring-1 focus:ring-indigo-500 appearance-none"
                  >
                      <option value="all">TODAS MIS ÁREAS</option>
                      {user?.allowedAreas.map(a => <option key={a} value={a}>{a.toUpperCase()}</option>)}
                  </select>
              </div>
              <button onClick={loadData} className="p-3 bg-slate-800 text-gray-400 hover:text-white rounded-xl border border-white/10 transition-colors">
                  <Loader size={18} className={loading ? 'animate-spin' : ''} />
              </button>
          </div>
      </div>

      {/* CONTENT GRID */}
      {loading ? (
          <div className="flex flex-col items-center justify-center py-40">
              <Loader className="animate-spin text-indigo-500 mb-4" size={48} />
              <p className="text-gray-500 font-bold uppercase tracking-widest text-xs">Sincronizando archivos del área...</p>
          </div>
      ) : filtered.length === 0 ? (
          <div className="text-center py-40 bg-slate-900 rounded-[2.5rem] border border-dashed border-white/10">
              <FileBox size={80} className="mx-auto text-slate-800 mb-6" />
              <p className="text-gray-400 font-bold text-lg uppercase tracking-tight">Sin archivos registrados</p>
              <p className="text-gray-600 text-sm mt-2 max-w-sm mx-auto uppercase tracking-tighter">Comparte formatos o documentos que ayuden a la operación de tu departamento.</p>
          </div>
      ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {filtered.map((item) => (
                  <div key={item.id} className="bg-slate-900 rounded-3xl border border-white/10 overflow-hidden shadow-xl hover:border-indigo-500/30 transition-all group flex flex-col h-full">
                      {/* Badge de Estado para Admin */}
                      {isAdmin && (
                          <div className={`px-4 py-1 text-[9px] font-black uppercase text-center border-b border-white/5 ${
                              item.status === 'pending' ? 'bg-amber-900/30 text-amber-400' : 
                              item.status === 'approved' ? 'bg-emerald-900/30 text-emerald-400' : 'bg-red-900/30 text-red-400'
                          }`}>
                              {item.status === 'pending' ? 'En Revisión de Gerencia' : 
                               item.status === 'approved' ? '✓ Publicado en Repositorio' : '✘ Aporte Denegado'}
                          </div>
                      )}

                      <div className="p-6 flex-1">
                          <div className="flex justify-between items-start mb-4">
                              <div className="p-3 bg-slate-950 rounded-2xl border border-white/5 shadow-inner">
                                  {getFileIcon(item.file_type)}
                              </div>
                              <span className="text-[9px] font-black bg-indigo-900/20 text-indigo-400 px-2 py-1 rounded border border-indigo-500/20 uppercase tracking-tighter">
                                  {item.area}
                              </span>
                          </div>

                          <h3 className="text-lg font-bold text-white mb-2 leading-tight uppercase line-clamp-1">{item.title}</h3>
                          <p className="text-xs text-gray-400 mb-6 line-clamp-3 leading-relaxed italic">
                              "{item.description || 'Sin descripción adicional.'}"
                          </p>

                          <div className="flex items-center gap-3 pt-4 border-t border-white/5">
                              <div className="w-8 h-8 rounded-full bg-slate-800 flex items-center justify-center font-bold text-[10px] text-indigo-300">
                                  {item.user_name.charAt(0)}
                              </div>
                              <div>
                                  <p className="text-[10px] font-black text-gray-200 uppercase">{item.user_name}</p>
                                  <p className="text-[9px] text-gray-600 font-mono uppercase">{new Date(item.created_at).toLocaleDateString()}</p>
                              </div>
                          </div>
                      </div>

                      {/* ACTIONS */}
                      <div className="p-4 bg-slate-950/50 border-t border-white/10 flex items-center justify-between gap-3">
                          <div className="flex gap-2">
                             <a 
                                href={item.file_url} 
                                target="_blank" 
                                rel="noreferrer"
                                className="flex items-center px-4 py-2 bg-indigo-600 hover:bg-indigo-500 text-white rounded-xl text-[10px] font-black uppercase transition-all shadow-sm"
                             >
                                <Download size={14} className="mr-1.5" />
                                Descargar
                             </a>
                          </div>

                          {isAdmin && (
                              <div className="flex gap-2">
                                  {item.status === 'pending' && (
                                      <>
                                        <button 
                                            onClick={() => handleModeration(item.id, 'approved')}
                                            className="p-2 bg-emerald-900/20 text-emerald-400 hover:bg-emerald-600 hover:text-white rounded-xl border border-emerald-500/30 transition-all"
                                            title="Aprobar"
                                        >
                                            <CheckCircle size={16} />
                                        </button>
                                        <button 
                                            onClick={() => handleModeration(item.id, 'rejected')}
                                            className="p-2 bg-red-900/20 text-red-400 hover:bg-red-600 hover:text-white rounded-xl border border-red-500/30 transition-all"
                                            title="Rechazar"
                                        >
                                            <XCircle size={16} />
                                        </button>
                                      </>
                                  )}
                                  <button 
                                    onClick={() => handleDelete(item.id)}
                                    className="p-2 bg-slate-800 text-gray-500 hover:bg-red-600 hover:text-white rounded-xl border border-white/5 transition-all"
                                    title="Eliminar permanentemente"
                                  >
                                      <Trash2 size={16} />
                                  </button>
                              </div>
                          )}
                      </div>
                  </div>
              ))}
          </div>
      )}

      {/* UPLOAD MODAL */}
      {showUploadModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-950/90 backdrop-blur-sm p-4">
