  // Multi-Area Management State
  const [areaManagerUser, setAreaManagerUser] = useState<User | null>(null);
  const [selectedAreas, setSelectedAreas] = useState<string[]>([]);
  const [isSavingAreas, setIsSavingAreas] = useState(false);

